import React from "react";
import "./InputGroup.css";

/**
 * @param {'success'|'error'} [validation] - Outlines the whole group (use with Input validation inside)
 */
function InputGroup({ left, right, children, className = "", validation }) {
  const classNames = [
    "ui-inputgroup",
    validation === "success" && "ui-inputgroup--validation-success",
    validation === "error" && "ui-inputgroup--validation-error",
    className,
  ]
    .filter(Boolean)
    .join(" ");
  return (
    <div className={classNames}>
      {left ? <span className="ui-inputgroup-addon ui-inputgroup-addon--left">{left}</span> : null}
      <span className="ui-inputgroup-input">{children}</span>
      {right ? <span className="ui-inputgroup-addon ui-inputgroup-addon--right">{right}</span> : null}
    </div>
  );
}

export default InputGroup;
