import React from "react";
import "./FormFeedback.css";

/**
 * Validation or hint text below a control.
 * @param {boolean} [invalid] - Error styling (role="alert")
 * @param {boolean} [valid] - Success styling (role="status")
 */
function FormFeedback({ children, className = "", invalid = false, valid = false, id, ...rest }) {
  const classNames = [
    "ui-form-feedback",
    invalid && "ui-form-feedback--invalid",
    valid && "ui-form-feedback--valid",
    className,
  ]
    .filter(Boolean)
    .join(" ");
  return (
    <div id={id} className={classNames} role={invalid ? "alert" : valid ? "status" : undefined} {...rest}>
      {children}
    </div>
  );
}

export default FormFeedback;
