import React from "react";
import "./Checkbox.css";

/**
 * Checkbox with label and optional description.
 * @param {boolean} checked - Controlled checked state
 * @param {function} onChange - (e) => void
 * @param {boolean} disabled
 * @param {string} label
 * @param {string} id - For linking label
 * @param {string} className
 */
function Checkbox({
  checked = false,
  onChange,
  disabled = false,
  label,
  id: idProp,
  className = "",
  indeterminate,
  invalid = false,
  feedback,
  ...rest
}) {
  const id = idProp || `ui-checkbox-${React.useId().replace(/:/g, "")}`;
  const inputRef = React.useRef(null);

  React.useEffect(() => {
    if (inputRef.current) {
      inputRef.current.indeterminate = !!indeterminate;
    }
  }, [indeterminate]);

  const feedbackId = feedback ? `${id}-feedback` : undefined;

  const classNames = [
    "ui-checkbox-wrapper",
    disabled && "ui-checkbox-wrapper--disabled",
    invalid && "ui-checkbox-wrapper--invalid",
    className,
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <div className={classNames}>
      <label className="ui-checkbox-label" htmlFor={id}>
        <input
          ref={inputRef}
          id={id}
          type="checkbox"
          className="ui-checkbox"
          checked={checked}
          onChange={onChange}
          disabled={disabled}
          aria-checked={indeterminate ? "mixed" : checked}
          aria-invalid={invalid}
          aria-describedby={feedbackId}
          {...rest}
        />
        <span className="ui-checkbox-box" aria-hidden="true" />
        {label ? <span className="ui-checkbox-text">{label}</span> : null}
      </label>
      {feedback ? (
        <span id={feedbackId} className="ui-checkbox-feedback" role="alert">
          {feedback}
        </span>
      ) : null}
    </div>
  );
}

export default Checkbox;
