import React from "react";
import "./Input.css";

function IconValid({ className }) {
  return (
    <svg className={className} width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden>
      <path
        d="M13.5 4.5L6.5 11.5L3 8"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function IconInvalid({ className }) {
  return (
    <svg className={className} width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden>
      <circle cx="8" cy="8" r="6.5" stroke="currentColor" strokeWidth="1.5" />
      <path d="M8 4.75V8.25M8 10.5v.01" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" />
    </svg>
  );
}

/**
 * Text input with optional label, validation states (success / error), and inline icons.
 * @param {string} [error] - Error message; also sets error styling (same as validation="error")
 * @param {'success'|'error'} [validation] - Visual validation state (ignored if `error` is set)
 * @param {string} [validationMessage] - Message under the field for validation (defaults to "Looks good!" for success)
 */
function Input({
  label,
  error,
  validation,
  validationMessage,
  type = "text",
  placeholder,
  disabled = false,
  id: idProp,
  className = "",
  ...rest
}) {
  const id = idProp || `ui-input-${React.useId().replace(/:/g, "")}`;
  const mode = error || validation === "error" ? "error" : validation === "success" ? "success" : null;
  const feedback =
    error ||
    (mode === "success" ? (validationMessage ?? "Looks good!") : null) ||
    (mode === "error" ? validationMessage : null);
  const feedbackId = feedback ? `${id}-feedback` : undefined;

  const inputClass = [
    "ui-input",
    mode === "error" && "ui-input--error",
    mode === "success" && "ui-input--success",
    mode && "ui-input--has-validation-icon",
    disabled && "ui-input--disabled",
    className,
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <div className="ui-input-wrapper">
      {label ? (
        <label htmlFor={id} className="ui-input-label">
          {label}
        </label>
      ) : null}
      <div className={["ui-input-control", mode && `ui-input-control--${mode}`].filter(Boolean).join(" ")}>
        <input
          id={id}
          type={type}
          className={inputClass}
          placeholder={placeholder}
          disabled={disabled}
          aria-invalid={mode === "error"}
          aria-describedby={feedbackId}
          {...rest}
        />
        {mode === "success" ? <IconValid className="ui-input__icon ui-input__icon--valid" /> : null}
        {mode === "error" ? <IconInvalid className="ui-input__icon ui-input__icon--invalid" /> : null}
      </div>
      {feedback ? (
        <span
          id={feedbackId}
          className={["ui-input-feedback", mode === "error" && "ui-input-feedback--error", mode === "success" && "ui-input-feedback--success"]
            .filter(Boolean)
            .join(" ")}
          role={mode === "error" ? "alert" : "status"}
        >
          {feedback}
        </span>
      ) : null}
    </div>
  );
}

export default Input;
